-- Create "production_orders" table
CREATE TABLE "production_orders" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "order_no" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'DRAFT',
  "version" bigint NOT NULL DEFAULT 1,
  "planned_start_at" timestamptz NULL,
  "planned_end_at" timestamptz NULL,
  "note" character varying NULL,
  "released_at" timestamptz NULL,
  "closed_at" timestamptz NULL,
  "close_reason" character varying NULL,
  "cancelled_at" timestamptz NULL,
  "cancel_reason" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "created_by" bigint NOT NULL,
  "released_by" bigint NULL,
  "closed_by" bigint NULL,
  "cancelled_by" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "production_orders_admin_users_canceller" FOREIGN KEY ("cancelled_by") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_orders_admin_users_closer" FOREIGN KEY ("closed_by") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_orders_admin_users_creator" FOREIGN KEY ("created_by") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_orders_admin_users_releaser" FOREIGN KEY ("released_by") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_orders_cancel_actor_pair" CHECK (((cancelled_by IS NULL) AND (cancelled_at IS NULL)) OR ((cancelled_by IS NOT NULL) AND (cancelled_at IS NOT NULL))),
  CONSTRAINT "production_orders_cancel_reason_present" CHECK (((status)::text <> 'CANCELLED'::text) OR ((cancel_reason IS NOT NULL) AND ((length(TRIM(BOTH FROM cancel_reason)) >= 1) AND (length(TRIM(BOTH FROM cancel_reason)) <= 255)))),
  CONSTRAINT "production_orders_cancel_reason_scope" CHECK ((cancel_reason IS NULL) OR ((status)::text = 'CANCELLED'::text)),
  CONSTRAINT "production_orders_close_actor_pair" CHECK (((closed_by IS NULL) AND (closed_at IS NULL)) OR ((closed_by IS NOT NULL) AND (closed_at IS NOT NULL))),
  CONSTRAINT "production_orders_close_reason_scope" CHECK ((close_reason IS NULL) OR ((status)::text = 'CLOSED'::text)),
  CONSTRAINT "production_orders_lifecycle_bundle" CHECK ((((status)::text = 'DRAFT'::text) AND (released_by IS NULL) AND (released_at IS NULL) AND (closed_by IS NULL) AND (closed_at IS NULL) AND (cancelled_by IS NULL) AND (cancelled_at IS NULL)) OR (((status)::text = 'RELEASED'::text) AND (released_by IS NOT NULL) AND (released_at IS NOT NULL) AND (closed_by IS NULL) AND (closed_at IS NULL) AND (cancelled_by IS NULL) AND (cancelled_at IS NULL)) OR (((status)::text = 'CLOSED'::text) AND (released_by IS NOT NULL) AND (released_at IS NOT NULL) AND (closed_by IS NOT NULL) AND (closed_at IS NOT NULL) AND (cancelled_by IS NULL) AND (cancelled_at IS NULL)) OR (((status)::text = 'CANCELLED'::text) AND (closed_by IS NULL) AND (closed_at IS NULL) AND (cancelled_by IS NOT NULL) AND (cancelled_at IS NOT NULL))),
  CONSTRAINT "production_orders_order_no_present" CHECK ((length(TRIM(BOTH FROM order_no)) >= 1) AND (length(TRIM(BOTH FROM order_no)) <= 64)),
  CONSTRAINT "production_orders_planned_dates_ordered" CHECK ((planned_start_at IS NULL) OR (planned_end_at IS NULL) OR (planned_end_at >= planned_start_at)),
  CONSTRAINT "production_orders_release_actor_pair" CHECK (((released_by IS NULL) AND (released_at IS NULL)) OR ((released_by IS NOT NULL) AND (released_at IS NOT NULL))),
  CONSTRAINT "production_orders_status_allowed" CHECK ((status)::text = ANY ((ARRAY['DRAFT'::character varying, 'RELEASED'::character varying, 'CLOSED'::character varying, 'CANCELLED'::character varying])::text[])),
  CONSTRAINT "production_orders_version_positive" CHECK (version > 0)
);
-- Create index "productionorder_created_by_created_at" to table: "production_orders"
CREATE INDEX "productionorder_created_by_created_at" ON "production_orders" ("created_by", "created_at");
-- Create index "productionorder_order_no" to table: "production_orders"
CREATE UNIQUE INDEX "productionorder_order_no" ON "production_orders" ("order_no");
-- Create index "productionorder_planned_end_at" to table: "production_orders"
CREATE INDEX "productionorder_planned_end_at" ON "production_orders" ("planned_end_at");
-- Create index "productionorder_status_planned_start_at" to table: "production_orders"
CREATE INDEX "productionorder_status_planned_start_at" ON "production_orders" ("status", "planned_start_at");
-- Create "production_order_events" table
CREATE TABLE "production_order_events" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "command_key" character varying NOT NULL,
  "from_status" character varying NULL,
  "to_status" character varying NOT NULL,
  "order_version" bigint NOT NULL,
  "idempotency_key" character varying NOT NULL,
  "intent_hash" character varying NOT NULL,
  "result_contract" character varying NOT NULL,
  "mutation_result" jsonb NOT NULL,
  "reason" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "production_order_id" bigint NOT NULL,
  "actor_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "production_order_events_admin_users_actor" FOREIGN KEY ("actor_id") REFERENCES "admin_users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_events_production_orders_events" FOREIGN KEY ("production_order_id") REFERENCES "production_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_events_command_allowed" CHECK ((command_key)::text = ANY ((ARRAY['CREATE'::character varying, 'SAVE'::character varying, 'RELEASE'::character varying, 'CLOSE'::character varying, 'CANCEL'::character varying])::text[])),
  CONSTRAINT "production_order_events_contract_v1" CHECK ((result_contract)::text = 'production.order-mutation-result/v1'::text),
  CONSTRAINT "production_order_events_create_shape" CHECK ((((command_key)::text = 'CREATE'::text) AND (from_status IS NULL) AND ((to_status)::text = 'DRAFT'::text) AND (order_version = 1)) OR (((command_key)::text <> 'CREATE'::text) AND (from_status IS NOT NULL))),
  CONSTRAINT "production_order_events_from_status_allowed" CHECK ((from_status IS NULL) OR ((from_status)::text = ANY ((ARRAY['DRAFT'::character varying, 'RELEASED'::character varying, 'CLOSED'::character varying, 'CANCELLED'::character varying])::text[]))),
  CONSTRAINT "production_order_events_hash_length" CHECK (length((intent_hash)::text) = 64),
  CONSTRAINT "production_order_events_key_present" CHECK ((length(TRIM(BOTH FROM idempotency_key)) >= 1) AND (length(TRIM(BOTH FROM idempotency_key)) <= 128)),
  CONSTRAINT "production_order_events_reason_scope" CHECK ((((command_key)::text <> ALL ((ARRAY['CLOSE'::character varying, 'CANCEL'::character varying])::text[])) AND (reason IS NULL)) OR ((command_key)::text = 'CLOSE'::text) OR (((command_key)::text = 'CANCEL'::text) AND (reason IS NOT NULL) AND ((length(TRIM(BOTH FROM reason)) >= 1) AND (length(TRIM(BOTH FROM reason)) <= 255)))),
  CONSTRAINT "production_order_events_to_status_allowed" CHECK ((to_status)::text = ANY ((ARRAY['DRAFT'::character varying, 'RELEASED'::character varying, 'CLOSED'::character varying, 'CANCELLED'::character varying])::text[])),
  CONSTRAINT "production_order_events_version_positive" CHECK (order_version > 0)
);
-- Create index "productionorderevent_actor_id_command_key_idempotency_key" to table: "production_order_events"
CREATE UNIQUE INDEX "productionorderevent_actor_id_command_key_idempotency_key" ON "production_order_events" ("actor_id", "command_key", "idempotency_key") WHERE ((command_key)::text = 'CREATE'::text);
-- Create index "productionorderevent_production_order_id_actor_id_command_key_i" to table: "production_order_events"
CREATE UNIQUE INDEX "productionorderevent_production_order_id_actor_id_command_key_i" ON "production_order_events" ("production_order_id", "actor_id", "command_key", "idempotency_key") WHERE ((command_key)::text <> 'CREATE'::text);
-- Create index "productionorderevent_production_order_id_created_at" to table: "production_order_events"
CREATE INDEX "productionorderevent_production_order_id_created_at" ON "production_order_events" ("production_order_id", "created_at");
-- Create index "productionorderevent_production_order_id_order_version" to table: "production_order_events"
CREATE UNIQUE INDEX "productionorderevent_production_order_id_order_version" ON "production_order_events" ("production_order_id", "order_version");
-- Create "production_order_items" table
CREATE TABLE "production_order_items" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "line_no" bigint NOT NULL,
  "planned_quantity" numeric(20,6) NOT NULL,
  "product_code_snapshot" character varying NULL,
  "product_name_snapshot" character varying NULL,
  "sku_code_snapshot" character varying NULL,
  "unit_name_snapshot" character varying NULL,
  "bom_version_snapshot" character varying NULL,
  "note" character varying NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "production_order_id" bigint NOT NULL,
  "product_id" bigint NOT NULL,
  "product_sku_id" bigint NULL,
  "unit_id" bigint NOT NULL,
  "sales_order_item_id" bigint NULL,
  "bom_header_id" bigint NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "production_order_items_bom_headers_bom_header" FOREIGN KEY ("bom_header_id") REFERENCES "bom_headers" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_items_product_skus_product_sku" FOREIGN KEY ("product_sku_id") REFERENCES "product_skus" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_items_production_orders_items" FOREIGN KEY ("production_order_id") REFERENCES "production_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_items_products_product" FOREIGN KEY ("product_id") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_items_sales_order_items_sales_order_item" FOREIGN KEY ("sales_order_item_id") REFERENCES "sales_order_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_items_units_unit" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_items_bom_header_positive" CHECK ((bom_header_id IS NULL) OR (bom_header_id > 0)),
  CONSTRAINT "production_order_items_line_no_positive" CHECK (line_no > 0),
  CONSTRAINT "production_order_items_product_id_positive" CHECK (product_id > 0),
  CONSTRAINT "production_order_items_quantity_positive" CHECK (planned_quantity > (0)::numeric),
  CONSTRAINT "production_order_items_sales_line_positive" CHECK ((sales_order_item_id IS NULL) OR (sales_order_item_id > 0)),
  CONSTRAINT "production_order_items_sku_id_positive" CHECK ((product_sku_id IS NULL) OR (product_sku_id > 0))
);
-- Create index "productionorderitem_bom_header_id" to table: "production_order_items"
CREATE INDEX "productionorderitem_bom_header_id" ON "production_order_items" ("bom_header_id");
-- Create index "productionorderitem_product_id_product_sku_id" to table: "production_order_items"
CREATE INDEX "productionorderitem_product_id_product_sku_id" ON "production_order_items" ("product_id", "product_sku_id");
-- Create index "productionorderitem_production_order_id_line_no" to table: "production_order_items"
CREATE UNIQUE INDEX "productionorderitem_production_order_id_line_no" ON "production_order_items" ("production_order_id", "line_no");
-- Create index "productionorderitem_sales_order_item_id" to table: "production_order_items"
CREATE INDEX "productionorderitem_sales_order_item_id" ON "production_order_items" ("sales_order_item_id");
